// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section id=\"intro\">\n<div class=\"section-header\">\n<div class=\"section-num\">01</div>\n<div class=\"section-title-group\">\n<h2>What is <span class=\"tone-info\">React</span>?</h2>\n<p>The philosophical foundation \u2014 understanding React's worldview before touching code</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>React is not just a library. It is a <strong>paradigm shift</strong> in how you think about building UIs. In vanilla JS, you imperatively manipulate the DOM \u2014 \"find this element, change its text, add this class.\" React inverts this: you describe <em>what the UI should look like</em> for a given state, and React figures out how to make it so. This is the leap from imperative to <strong>declarative programming</strong>.</p>\n<div>\u2014 The Core Philosophy of React</div>\n</div>\n<div class=\"two-col\">\n<div>\n<h3> Vanilla JS Way</h3>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">vanilla.js</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// You tell the DOM EXACTLY what to do</span>\n<span>// (Imperative \u2014 step by step commands)</span>\n\n<span>const</span> <span>btn</span> = document.<span>getElementById</span>(<span>'btn'</span>);\n<span>const</span> <span>count</span> = document.<span>getElementById</span>(<span>'count'</span>);\n<span>let</span> <span>n</span> = <span>0</span>;\n\nbtn.<span>addEventListener</span>(<span>'click'</span>, () =&gt; {\n n++;\n count.textContent = n; <span>// manually update DOM</span>\n <span>if</span> (n &gt; <span>10</span>) {\n count.style.color = <span>'red'</span>; <span>// manual style</span>\n }\n});</pre></div>\n</div>\n</div>\n<div>\n<h3> React Way</h3>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Counter.jsx</span>\n<span class=\"code-lang\">JSX</span>\n</div>\n<div class=\"code-body\"><pre><span>// You DESCRIBE what the UI looks like</span>\n<span>// (Declarative \u2014 describe the outcome)</span>\n\n<span>function</span> <span>Counter</span>() {\n <span>const</span> [<span>n</span>, <span>setN</span>] = <span>useState</span>(<span>0</span>);\n\n <span>return</span> (\n &lt;<span>div</span>&gt;\n &lt;<span>p</span> <span>style</span>=<span>{{color: n &gt; 10 ? 'red' : 'black'}}</span>&gt;\n {n}\n &lt;/<span>p</span>&gt;\n &lt;<span>button</span> <span>onClick</span>=<span>{() =&gt; setN(n + 1)}</span>&gt;+&lt;/<span>button</span>&gt;\n &lt;/<span>div</span>&gt;\n );\n}</pre></div>\n</div>\n</div>\n</div>\n<div class=\"concept-grid\">\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Component-Based</h3>\n<p>UIs are built from isolated, reusable pieces called components. Think of them like LEGO bricks \u2014 each has its own logic and appearance, and you compose them to build complex UIs.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Unidirectional Data Flow</h3>\n<p>Data flows in one direction: down from parent to child via props. This makes apps predictable and debugging straightforward \u2014 you always know where data came from.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>Virtual DOM</h3>\n<p>React maintains an in-memory representation of the UI. On state change, it diffs the new vs old virtual DOM and applies only the minimum real DOM changes needed. Efficient and fast.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-tip\"></div>\n<h3>Just JavaScript</h3>\n<p>React has no special template language (beyond JSX, which compiles to JS). You use real JS \u2014 loops, conditions, functions \u2014 to build your UI. No Django-style template filters needed.</p>\n</div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Coming from Django Templates?</h4>\n<p>In Django, templates (HTML files with <code>{% %}</code> tags) are server-rendered. React components are JavaScript functions that return UI descriptions, rendered in the browser (or on a server with SSR). The mental model shifts from \"server sends HTML\" to \"server sends JS that builds HTML.\"</p>\n</div>\n</div>\n</section>\n<section id=\"mental-models\">\n<div class=\"section-header\">\n<div class=\"section-num\">02</div>\n<div class=\"section-title-group\">\n<h2>The Right <span class=\"tone-info\">Mental Models</span></h2>\n<p>Before writing a single line, understand how React thinks about the world</p>\n</div>\n</div>\n<div class=\"mental-model\">\n<h3> Mental Model #1 \u2014 UI as a Function of State</h3>\n<p>This is the most fundamental insight in React. Think of your entire UI as a mathematical function:</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>// The React Equation</span>\n<span>UI</span> = <span>f</span>(<span>state</span>)\n\n<span>// Given the same state, you ALWAYS get the same UI.</span>\n<span>// React's job: make the UI match state efficiently.</span>\n\n<span>// state = { user: \"Alice\", count: 5, isLoggedIn: true }</span>\n<span>// \u2192 specific UI structure</span>\n\n<span>// state = { user: \"Alice\", count: 6, isLoggedIn: true }</span>\n<span>// \u2192 same structure, just count changed \u2192 minimal DOM update</span></pre></div>\n</div>\n<ul>\n<li>You never manually touch the DOM. You update state, and React re-renders.</li>\n<li>Components are <strong>pure functions</strong> conceptually \u2014 same input (state + props) \u2192 same output (UI).</li>\n<li>This makes React apps testable, predictable, and debuggable.</li>\n</ul>\n</div>\n<div class=\"mental-model\">\n<h3> Mental Model #2 \u2014 The Component Tree</h3>\n<p>Every React app is a tree of components. The root is usually <code>&lt;App /&gt;</code>. Data and events flow through this tree in defined patterns:</p>\n<div>\n<svg viewbox=\"0 0 600 280\" xmlns=\"http://www.w3.org/2000/svg\">\n<!-- Root -->\n<rect fill=\"#1E2533\" height=\"44\" rx=\"8\" stroke=\"#00D4FF\" stroke-width=\"1.5\" width=\"160\" x=\"220\" y=\"10\"></rect>\n<text fill=\"#00D4FF\" font-family=\"JetBrains Mono\" font-size=\"14\" font-weight=\"bold\" text-anchor=\"middle\" x=\"300\" y=\"38\">&lt;App /&gt;</text>\n<!-- Level 2 -->\n<rect fill=\"#1E2533\" height=\"44\" rx=\"8\" stroke=\"#7C3AED\" stroke-width=\"1.5\" width=\"150\" x=\"60\" y=\"90\"></rect>\n<text fill=\"#9B5DE5\" font-family=\"JetBrains Mono\" font-size=\"12\" text-anchor=\"middle\" x=\"135\" y=\"118\">&lt;Navbar /&gt;</text>\n<rect fill=\"#1E2533\" height=\"44\" rx=\"8\" stroke=\"#7C3AED\" stroke-width=\"1.5\" width=\"150\" x=\"225\" y=\"90\"></rect>\n<text fill=\"#9B5DE5\" font-family=\"JetBrains Mono\" font-size=\"12\" text-anchor=\"middle\" x=\"300\" y=\"118\">&lt;Main /&gt;</text>\n<rect fill=\"#1E2533\" height=\"44\" rx=\"8\" stroke=\"#7C3AED\" stroke-width=\"1.5\" width=\"150\" x=\"390\" y=\"90\"></rect>\n<text fill=\"#9B5DE5\" font-family=\"JetBrains Mono\" font-size=\"12\" text-anchor=\"middle\" x=\"465\" y=\"118\">&lt;Footer /&gt;</text>\n<!-- Level 3 -->\n<rect fill=\"#1E2533\" height=\"40\" rx=\"8\" stroke=\"#00FF88\" stroke-width=\"1.5\" width=\"130\" x=\"155\" y=\"176\"></rect>\n<text fill=\"#00FF88\" font-family=\"JetBrains Mono\" font-size=\"11\" text-anchor=\"middle\" x=\"220\" y=\"200\">&lt;Sidebar /&gt;</text>\n<rect fill=\"#1E2533\" height=\"40\" rx=\"8\" stroke=\"#00FF88\" stroke-width=\"1.5\" width=\"130\" x=\"300\" y=\"176\"></rect>\n<text fill=\"#00FF88\" font-family=\"JetBrains Mono\" font-size=\"11\" text-anchor=\"middle\" x=\"365\" y=\"200\">&lt;Content /&gt;</text>\n<!-- Level 4 -->\n<rect fill=\"#1E2533\" height=\"30\" rx=\"6\" stroke=\"#FFB347\" stroke-width=\"1\" width=\"120\" x=\"280\" y=\"248\"></rect>\n<text fill=\"#FFB347\" font-family=\"JetBrains Mono\" font-size=\"10\" text-anchor=\"middle\" x=\"340\" y=\"268\">&lt;PostCard /&gt; \u00d7n</text>\n<!-- Lines -->\n<line stroke=\"#4A5568\" stroke-dasharray=\"4,3\" stroke-width=\"1.5\" x1=\"300\" x2=\"135\" y1=\"54\" y2=\"90\"></line>\n<line stroke=\"#4A5568\" stroke-dasharray=\"4,3\" stroke-width=\"1.5\" x1=\"300\" x2=\"300\" y1=\"54\" y2=\"90\"></line>\n<line stroke=\"#4A5568\" stroke-dasharray=\"4,3\" stroke-width=\"1.5\" x1=\"300\" x2=\"465\" y1=\"54\" y2=\"90\"></line>\n<line stroke=\"#4A5568\" stroke-dasharray=\"4,3\" stroke-width=\"1\" x1=\"300\" x2=\"220\" y1=\"134\" y2=\"176\"></line>\n<line stroke=\"#4A5568\" stroke-dasharray=\"4,3\" stroke-width=\"1\" x1=\"300\" x2=\"365\" y1=\"134\" y2=\"176\"></line>\n<line stroke=\"#4A5568\" stroke-dasharray=\"4,3\" stroke-width=\"1\" x1=\"365\" x2=\"340\" y1=\"216\" y2=\"248\"></line>\n<!-- Props arrow -->\n<text fill=\"#00D4FF\" font-family=\"Inter\" font-size=\"10\" x=\"480\" y=\"68\">props \u2193</text>\n<text fill=\"#FFB347\" font-family=\"Inter\" font-size=\"10\" x=\"480\" y=\"80\">events \u2191</text>\n</svg>\n</div>\n<ul>\n<li><strong>Props flow DOWN</strong> \u2014 parent passes data to child.</li>\n<li><strong>Events bubble UP</strong> \u2014 child calls parent's callback function.</li>\n<li><strong>State lives at the right level</strong> \u2014 in the component that needs it, or its nearest common ancestor.</li>\n</ul>\n</div>\n<div class=\"mental-model\">\n<h3> Mental Model #3 \u2014 React's Rendering Contract</h3>\n<p>React renders (calls your component function) when state or props change. Your component must behave like a <strong>pure function</strong>:</p>\n<ul>\n<li>Given the same props + state \u2192 always return the same JSX</li>\n<li>Never mutate props or state directly</li>\n<li>No side effects during render (use <code>useEffect</code> for those)</li>\n</ul>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>The Golden Rule</h4>\n<p>If you mutate state directly (<code>state.count = 5</code>), React won't know a change happened and won't re-render. Always use the setter function: <code>setState(newValue)</code>. This is fundamentally different from vanilla JS.</p>\n</div>\n</div>\n</div>\n</section>\n<section id=\"setup\">\n<div class=\"section-header\">\n<div class=\"section-num\">03</div>\n<div class=\"section-title-group\">\n<h2>Project <span>Setup</span></h2>\n<p>Bootstrapping a React project the modern way \u2014 Vite over Create React App</p>\n</div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Vite vs Create React App</h4>\n<p>In 2024+, use <strong>Vite</strong>. CRA is deprecated. Vite starts in milliseconds (vs ~30s for CRA), uses native ES modules, and has first-class TypeScript support. For full-stack, consider <strong>Next.js</strong> or <strong>Remix</strong>.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">terminal</span>\n<span class=\"code-lang\">BASH</span>\n</div>\n<div class=\"code-body\"><pre><span># Create a new React + TypeScript + Vite project</span>\nnpm create vite@latest my-app -- --template react-ts\n<span>cd</span> my-app\nnpm install\n\n<span># OR with JavaScript only</span>\nnpm create vite@latest my-app -- --template react\n\n<span># Start dev server (instant hot reload)</span>\nnpm run dev\n\n<span># Build for production</span>\nnpm run build\n\n<span># Preview production build locally</span>\nnpm run preview</pre></div>\n</div>\n<h3>Project Structure (The Right Way)</h3>\n<div class=\"tree\">\n<pre><span>my-app/</span>\n\u251c\u2500\u2500 <span>public/</span> <span>\u2190 static assets (favicon, images)</span>\n\u251c\u2500\u2500 <span>src/</span>\n\u2502 \u251c\u2500\u2500 <span>components/</span> <span>\u2190 reusable UI components</span>\n\u2502 \u2502 \u251c\u2500\u2500 <span>ui/</span> <span>\u2190 generic: Button, Input, Modal</span>\n\u2502 \u2502 \u2514\u2500\u2500 <span>features/</span> <span>\u2190 domain: UserCard, ProductList</span>\n\u2502 \u251c\u2500\u2500 <span>pages/</span> <span>\u2190 route-level components</span>\n\u2502 \u2502 \u251c\u2500\u2500 <span>HomePage.tsx</span>\n\u2502 \u2502 \u2514\u2500\u2500 <span>ProfilePage.tsx</span>\n\u2502 \u251c\u2500\u2500 <span>hooks/</span> <span>\u2190 custom hooks: useAuth, useFetch</span>\n\u2502 \u251c\u2500\u2500 <span>context/</span> <span>\u2190 React Context providers</span>\n\u2502 \u251c\u2500\u2500 <span>services/</span> <span>\u2190 API calls (like Django views, but client-side)</span>\n\u2502 \u251c\u2500\u2500 <span>store/</span> <span>\u2190 Zustand/Redux state</span>\n\u2502 \u251c\u2500\u2500 <span>utils/</span> <span>\u2190 helper functions</span>\n\u2502 \u251c\u2500\u2500 <span>types/</span> <span>\u2190 TypeScript interfaces/types</span>\n\u2502 \u251c\u2500\u2500 <span>App.tsx</span> <span>\u2190 root component + routing</span>\n\u2502 \u251c\u2500\u2500 <span>main.tsx</span> <span>\u2190 entry point (like wsgi.py)</span>\n\u2502 \u2514\u2500\u2500 <span>index.css</span>\n\u251c\u2500\u2500 <span>index.html</span> <span>\u2190 single HTML file (React mounts here)</span>\n\u251c\u2500\u2500 <span>vite.config.ts</span> <span>\u2190 like Django's settings.py</span>\n\u251c\u2500\u2500 <span>tsconfig.json</span>\n\u2514\u2500\u2500 <span>package.json</span> <span>\u2190 like requirements.txt + manage.py</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">src/main.tsx</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>// Entry point \u2014 like Django's wsgi.py</span>\n<span>// React mounts the entire app into a single DOM element</span>\n\n<span>import</span> React <span>from</span> <span>'react'</span>\n<span>import</span> ReactDOM <span>from</span> <span>'react-dom/client'</span>\n<span>import</span> App <span>from</span> <span>'./App'</span>\n<span>import</span> <span>'./index.css'</span>\n\nReactDOM.<span>createRoot</span>(document.<span>getElementById</span>(<span>'root'</span>)!)\n .<span>render</span>(\n &lt;<span>React.StrictMode</span>&gt; <span>// doubles renders in dev to catch bugs</span>\n &lt;<span>App</span> /&gt;\n &lt;/<span>React.StrictMode</span>&gt;\n )</pre></div>\n</div>\n</section>\n<section id=\"jsx\">\n<div class=\"section-header\">\n<div class=\"section-num\">04</div>\n<div class=\"section-title-group\">\n<h2>JSX <span class=\"tone-info\">Deep Dive</span></h2>\n<p>JSX is not HTML. It's JavaScript with a syntactic sugar for describing UI trees.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>JSX looks like HTML, but it compiles to <code>React.createElement()</code> calls. When you write <code>&lt;Button color=\"blue\"&gt;Click&lt;/Button&gt;</code>, Babel transforms it into <code>React.createElement(Button, {'{'}color: \"blue\"{'}'}, \"Click\")</code>. JSX is just a nicer way to write function calls that build a JavaScript object tree.</p>\n</div>\n<div class=\"two-col\">\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">JSX (what you write)</span>\n<span class=\"code-lang\">JSX</span>\n</div>\n<div class=\"code-body\"><pre>&lt;<span>div</span> <span>className</span>=<span>\"card\"</span>&gt;\n &lt;<span>h1</span>&gt;{title}&lt;/<span>h1</span>&gt;\n &lt;<span>Button</span>\n <span>onClick</span>=<span>{handleClick}</span>\n <span>disabled</span>=<span>{isLoading}</span>\n &gt;\n Submit\n &lt;/<span>Button</span>&gt;\n&lt;/<span>div</span>&gt;</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Compiled JS (what React sees)</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre>React.<span>createElement</span>(<span>'div'</span>, \n {<span>className</span>: <span>\"card\"</span>},\n React.<span>createElement</span>(<span>'h1'</span>, <span>null</span>, title),\n React.<span>createElement</span>(Button, {\n <span>onClick</span>: handleClick,\n <span>disabled</span>: isLoading\n }, <span>\"Submit\"</span>)\n)</pre></div>\n</div>\n</div>\n<h3>JSX Rules &amp; Differences from HTML</h3>\n<table class=\"comparison-table\">\n<thead>\n<tr>\n<th>HTML</th>\n<th>JSX</th>\n<th>Reason</th>\n</tr>\n</thead>\n<tbody>\n<tr><td><code>class=\"foo\"</code></td><td><code>className=\"foo\"</code></td><td><code>class</code> is a reserved JS keyword</td></tr>\n<tr><td><code>for=\"id\"</code></td><td><code>htmlFor=\"id\"</code></td><td><code>for</code> is a reserved JS keyword</td></tr>\n<tr><td><code>onclick=\"fn()\"</code></td><td><code>onClick={fn}</code></td><td>camelCase + pass function reference</td></tr>\n<tr><td><code>style=\"color: red\"</code></td><td><code>style={{'{'}color: 'red'{'}'}}</code></td><td>Style is a JS object, not a string</td></tr>\n<tr><td><code>&lt;input&gt;</code></td><td><code>&lt;input /&gt;</code></td><td>JSX: all tags must be closed</td></tr>\n<tr><td>Multiple root elements OK</td><td>Must have ONE root element</td><td>Use <code>&lt;Fragment&gt;</code> or <code>&lt;&gt;...&lt;/&gt;</code></td></tr>\n<tr><td><code>&lt;!-- comment --&gt;</code></td><td><code>{'{'}/* comment */{'}'}</code></td><td>JS comment syntax inside <code>{'{}'}</code></td></tr>\n</tbody>\n</table>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">JSX Expressions &amp; Patterns</span>\n<span class=\"code-lang\">JSX</span>\n</div>\n<div class=\"code-body\"><pre><span>function</span> <span>ProfileCard</span>({ <span>user</span>, <span>posts</span>, <span>isAdmin</span> }) {\n <span>return</span> (\n <span>// Fragment: no extra DOM node</span>\n &lt;&gt;\n <span>// Embed any JS expression with {}</span>\n &lt;<span>h1</span>&gt;{user.name.toUpperCase()}&lt;/<span>h1</span>&gt;\n\n <span>// Conditional rendering</span>\n {isAdmin <span>&amp;&amp;</span> &lt;<span>span</span>&gt;Admin&lt;/<span>span</span>&gt;}\n {isAdmin ? &lt;<span>AdminBadge</span> /&gt; : &lt;<span>UserBadge</span> /&gt;}\n\n <span>// List rendering \u2014 always use 'key'!</span>\n &lt;<span>ul</span>&gt;\n {posts.<span>map</span>(post =&gt; (\n &lt;<span>li</span> <span>key</span>=<span>{post.id}</span>&gt;{post.title}&lt;/<span>li</span>&gt;\n ))}\n &lt;/<span>ul</span>&gt;\n\n <span>// Inline style (object, not string)</span>\n &lt;<span>div</span> <span>style</span>=<span>{{fontSize: 14, color: '#ccc'}}</span>&gt;\n {user.bio}\n &lt;/<span>div</span>&gt;\n &lt;/&gt;\n );\n}</pre></div>\n</div>\n</section>\n<section id=\"components\">\n<div class=\"section-header\">\n<div class=\"section-num\">05</div>\n<div class=\"section-title-group\">\n<h2><span class=\"tone-info\">Components</span> \u2014 The Atom of React</h2>\n<p>Everything in React is a component. Understand them deeply and you understand React.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>A component is a JavaScript function that takes some inputs (called <strong>props</strong>) and returns a description of what should appear on screen (JSX). That's it. There's no magic \u2014 just functions. The power comes from <em>composing</em> these functions to build complex interfaces from simple, isolated pieces.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">components/Button.tsx</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>// A component is just a function \u2014 nothing magical</span>\n<span>// Convention: PascalCase name (required to distinguish from HTML tags)</span>\n\n<span>interface</span> <span>ButtonProps</span> {\n <span>children</span>: React.ReactNode; <span>// anything renderable</span>\n <span>onClick</span>?: () =&gt; <span>void</span>;\n <span>variant</span>?: <span>'primary'</span> | <span>'secondary'</span> | <span>'danger'</span>;\n <span>disabled</span>?: <span>boolean</span>;\n}\n\n<span>export function</span> <span>Button</span>({\n children,\n onClick,\n variant = <span>'primary'</span>, <span>// default prop value</span>\n disabled = <span>false</span>,\n}: ButtonProps) {\n <span>const</span> <span>baseClass</span> = <span>'btn'</span>;\n <span>const</span> <span>variantClass</span> = <span>`btn--</span>${variant}<span>`</span>;\n\n <span>return</span> (\n &lt;<span>button</span>\n <span>className</span>=<span>{`${baseClass} ${variantClass}`}</span>\n <span>onClick</span>=<span>{onClick}</span>\n <span>disabled</span>=<span>{disabled}</span>\n &gt;\n {children}\n &lt;/<span>button</span>&gt;\n );\n}\n\n<span>// Usage \u2014 compose in parent:</span>\n<span>// &lt;Button variant=\"danger\" onClick={handleDelete}&gt;</span>\n<span>// Delete Account</span>\n<span>// &lt;/Button&gt;</span></pre></div>\n</div>\n<div class=\"divider\"><div class=\"divider-line\"></div><div class=\"divider-text\">// Component Patterns</div><div class=\"divider-line\"></div></div>\n<h3>Component Composition Patterns</h3>\n<div class=\"concept-grid\">\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Container Pattern</h3>\n<p>A \"wrapper\" component that provides layout/styling. Uses <code>children</code> prop to render whatever's placed inside it \u2014 like a Django template block.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Render Props</h3>\n<p>A component that accepts a function as a prop, calling it to determine what to render. Enables flexible, reusable logic sharing without HOCs.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>Compound Components</h3>\n<p>A set of components that work together (e.g., <code>&lt;Select&gt;</code> + <code>&lt;Option&gt;</code>). Share state implicitly via Context without prop-drilling.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-tip\"></div>\n<h3>Higher-Order Components</h3>\n<p>A function that takes a component and returns an enhanced version. Like Python decorators for components. Common for auth: <code>withAuth(Dashboard)</code>.</p>\n</div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Component Design Rules</h4>\n<p>1. A component should do ONE thing. If it's doing too much, split it. 2. Keep components small \u2014 ideally under 150 lines. 3. Smart components (with state/logic) vs Dumb/Presentational components (just render). 4. Name components by what they ARE, not what they DO: <code>UserCard</code> not <code>renderUser</code>.</p>\n</div>\n</div>\n</section>\n<section id=\"props\">\n<div class=\"section-header\">\n<div class=\"section-num\">06</div>\n<div class=\"section-title-group\">\n<h2><span class=\"tone-tip\">Props</span> \u2014 The Communication Channel</h2>\n<p>Props are how components communicate. Like function arguments \u2014 read-only, explicit, predictable.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>Props (short for \"properties\") are React's way of passing data from parent to child. They are <strong>immutable</strong> \u2014 a component must never modify its own props. This enforces the unidirectional data flow that makes React apps predictable. If you need to change data, lift state up and pass a setter down as a prop.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Props Patterns</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>// 1. Basic Props</span>\n<span>function</span> <span>Greeting</span>({ name, age }: { name: string; age: number }) {\n <span>return</span> &lt;<span>p</span>&gt;Hi {name}, you are {age} years old&lt;/<span>p</span>&gt;;\n}\n\n<span>// 2. children prop \u2014 anything between tags</span>\n<span>function</span> <span>Card</span>({ children, title }: { children: React.ReactNode; title: string }) {\n <span>return</span> (\n &lt;<span>div</span> <span>className</span>=<span>\"card\"</span>&gt;\n &lt;<span>h2</span>&gt;{title}&lt;/<span>h2</span>&gt;\n {children} <span>// renders whatever's placed between &lt;Card&gt;...&lt;/Card&gt;</span>\n &lt;/<span>div</span>&gt;\n );\n}\n\n<span>// 3. Spread props \u2014 pass all props to underlying element</span>\n<span>function</span> <span>Input</span>({ label, ...rest }: { label: string } <span>&amp;</span> React.InputHTMLAttributes&lt;HTMLInputElement&gt;) {\n <span>return</span> (\n &lt;<span>label</span>&gt;\n {label}\n &lt;<span>input</span> {...rest} /&gt; <span>// passes all other props (type, value, onChange, etc)</span>\n &lt;/<span>label</span>&gt;\n );\n}\n\n<span>// 4. Callback props \u2014 child calls parent's function</span>\n<span>function</span> <span>Parent</span>() {\n <span>const</span> [<span>value</span>, <span>setValue</span>] = <span>useState</span>(<span>''</span>);\n <span>return</span> &lt;<span>Child</span> <span>onChange</span>=<span>{setValue}</span> /&gt;; <span>// pass setter down</span>\n}\n\n<span>function</span> <span>Child</span>({ onChange }: { onChange: (val: string) =&gt; <span>void</span> }) {\n <span>return</span> &lt;<span>input</span> <span>onChange</span>=<span>{e =&gt; onChange(e.target.value)}</span> /&gt;;\n}</pre></div>\n</div>\n</section>\n<section id=\"state\">\n<div class=\"section-header\">\n<div class=\"section-num\">07</div>\n<div class=\"section-title-group\">\n<h2><span>State</span> \u2014 The Heart of Reactivity</h2>\n<p>State is memory. It's what makes your app dynamic and interactive.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>State is data that changes over time and causes the UI to re-render when it does. Unlike regular variables (which disappear when the function ends), React state <strong>persists</strong> between renders. When you call <code>setState</code>, React schedules a re-render \u2014 it calls your component function again, and you get a new snapshot of the UI for that new state.</p>\n</div>\n<div>\n<div class=\"sf-box\">\n<div class=\"sf-label\">Initial State</div>\n<div class=\"sf-val\">count = 0</div>\n</div>\n<div class=\"sf-arrow\">\u2192</div>\n<div class=\"sf-box\">\n<div class=\"sf-label\">User Action</div>\n<div class=\"sf-val\">onClick</div>\n</div>\n<div class=\"sf-arrow\">\u2192</div>\n<div class=\"sf-box\">\n<div class=\"sf-label\">setState Call</div>\n<div class=\"sf-val\">setCount(1)</div>\n</div>\n<div class=\"sf-arrow\">\u2192</div>\n<div class=\"sf-box\">\n<div class=\"sf-label\">Re-render</div>\n<div class=\"sf-val\">UI updates</div>\n</div>\n<div class=\"sf-arrow\">\u2192</div>\n<div class=\"sf-box\">\n<div class=\"sf-label\">New Snapshot</div>\n<div class=\"sf-val\">count = 1</div>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">State Patterns</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { useState } <span>from</span> <span>'react'</span>;\n\n<span>function</span> <span>TodoApp</span>() {\n <span>// Primitive state</span>\n <span>const</span> [<span>count</span>, <span>setCount</span>] = <span>useState</span>&lt;<span>number</span>&gt;(<span>0</span>);\n\n <span>// Object state \u2014 MUST replace entire object</span>\n <span>const</span> [<span>user</span>, <span>setUser</span>] = <span>useState</span>({ name: <span>'Alice'</span>, age: <span>30</span> });\n\n <span>// Array state \u2014 MUST return new array</span>\n <span>const</span> [<span>todos</span>, <span>setTodos</span>] = <span>useState</span>&lt;string[]&gt;([]);\n\n <span>// Correct: create NEW object with spread</span>\n <span>const</span> <span>updateName</span> = (name: <span>string</span>) =&gt; {\n <span>setUser</span>(prev =&gt; ({ ...prev, name })); <span>// functional update</span>\n };\n\n <span>// WRONG: mutating state directly</span>\n <span>// user.name = 'Bob'; // React won't re-render!</span>\n\n <span>// Correct: add to array</span>\n <span>const</span> <span>addTodo</span> = (text: <span>string</span>) =&gt; {\n <span>setTodos</span>(prev =&gt; [...prev, text]); <span>// NEW array</span>\n };\n\n <span>// Correct: remove from array</span>\n <span>const</span> <span>removeTodo</span> = (index: <span>number</span>) =&gt; {\n <span>setTodos</span>(prev =&gt; prev.<span>filter</span>((_, i) =&gt; i !== index));\n };\n\n <span>return</span> (\n &lt;<span>div</span>&gt;\n &lt;<span>p</span>&gt;Count: {count}&lt;/<span>p</span>&gt;\n &lt;<span>button</span> <span>onClick</span>=<span>{() =&gt; setCount(c =&gt; c + 1)}</span>&gt;+&lt;/<span>button</span>&gt;\n &lt;/<span>div</span>&gt;\n );\n}</pre></div>\n</div>\n<div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Pro Tip</div>\n<p>Use the <strong>functional update form</strong> <code>setState(prev =&gt; prev + 1)</code> when new state depends on old state. Avoids stale closure bugs with async operations.</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Pro Tip</div>\n<p>Group related state into one object: <code>useState({'{'} name, email, age {'}'})</code>. But unrelated state should be separate \u2014 React only re-renders when that specific state changes.</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Pro Tip</div>\n<p><strong>Lift state up</strong> when two components need to share state. Find their nearest common ancestor and put state there, passing it down as props.</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Warning</div>\n<p>State updates are <strong>asynchronous and batched</strong>. Calling <code>setCount(count + 1)</code> twice won't increment by 2 \u2014 use the functional form: <code>setCount(c =&gt; c + 1)</code> twice.</p>\n</div>\n</div>\n</section>\n<section id=\"lifecycle\">\n<div class=\"section-header\">\n<div class=\"section-num\">08</div>\n<div class=\"section-title-group\">\n<h2>Component <span class=\"tone-info\">Lifecycle</span></h2>\n<p>Every component is born, lives, and dies. React gives you hooks to tap into each phase.</p>\n</div>\n</div>\n<div>\n<div class=\"lc-phase\">\n<div class=\"lc-phase-title\">MOUNT</div>\n<span class=\"lc-hook\">Component created</span>\n<span class=\"lc-hook\">Initial render</span>\n<span class=\"lc-hook\">useEffect( , [])</span>\n</div>\n<div class=\"lc-phase\">\n<div class=\"lc-phase-title\">UPDATE</div>\n<span class=\"lc-hook\">State changes</span>\n<span class=\"lc-hook\">Props change</span>\n<span class=\"lc-hook\">useEffect( , [deps])</span>\n</div>\n<div class=\"lc-phase\">\n<div class=\"lc-phase-title\">UNMOUNT</div>\n<span class=\"lc-hook\">Component removed</span>\n<span class=\"lc-hook\">Cleanup needed</span>\n<span class=\"lc-hook\">return () =&gt; cleanup</span>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Lifecycle with useEffect</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { useState, useEffect } <span>from</span> <span>'react'</span>;\n\n<span>function</span> <span>DataComponent</span>({ userId }: { userId: number }) {\n <span>const</span> [<span>data</span>, <span>setData</span>] = <span>useState</span>(<span>null</span>);\n\n <span>// Runs ONCE after first render (componentDidMount)</span>\n <span>useEffect</span>(() =&gt; {\n <span>const</span> <span>controller</span> = <span>new</span> <span>AbortController</span>();\n <span>fetch</span>(<span>`/api/users/</span>${userId}<span>`</span>, { signal: controller.signal })\n .<span>then</span>(r =&gt; r.<span>json</span>())\n .<span>then</span>(<span>setData</span>);\n\n <span>// Cleanup: runs before next effect OR on unmount</span>\n <span>return</span> () =&gt; controller.<span>abort</span>();\n }, []); <span>// empty deps = run only on mount</span>\n\n <span>// Runs when userId changes (componentDidUpdate)</span>\n <span>useEffect</span>(() =&gt; {\n <span>fetchUser</span>(userId).<span>then</span>(<span>setData</span>);\n }, [userId]); <span>// re-runs when userId changes</span>\n\n <span>// Runs after EVERY render (rarely what you want)</span>\n <span>useEffect</span>(() =&gt; {\n document.title = <span>`User </span>${userId}<span>`</span>;\n }); <span>// no deps array = always</span>\n\n <span>return</span> &lt;<span>div</span>&gt;{data?.name}&lt;/<span>div</span>&gt;;\n}</pre></div>\n</div>\n</section>\n<section id=\"hooks\">\n<div class=\"section-header\">\n<div class=\"section-num\">09 \u2013 12</div>\n<div class=\"section-title-group\">\n<h2>Hooks \u2014 <span class=\"tone-info\">The Superpower</span></h2>\n<p>Hooks let function components use state, lifecycle, context, and more. The complete guide.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>Hooks are functions that \"hook into\" React's internal state and lifecycle system. They were introduced in React 16.8 to solve the problem of reusing stateful logic between components. The rule: hooks can only be called at the <strong>top level of a component</strong> (not inside loops, conditions, or nested functions). This allows React to consistently track hook calls between renders.</p>\n<div>// Rules of Hooks \u2014 enforced by eslint-plugin-react-hooks</div>\n</div>\n<div>\n<div class=\"hook-card\">\n<div class=\"hook-badge\">State</div>\n<div class=\"hook-name\">useState</div>\n<div class=\"hook-subtitle\">// local component state</div>\n<p>The most fundamental hook. Stores a value that persists between renders and triggers re-render when changed. Returns <code>[value, setter]</code>.</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>const</span> [<span>count</span>, <span>setCount</span>] = <span>useState</span>(<span>0</span>);\n<span>const</span> [<span>name</span>, <span>setName</span>] = <span>useState</span>&lt;<span>string</span>&gt;(<span>''</span>);\n<span>// lazy init for expensive computation:</span>\n<span>const</span> [<span>data</span>, <span>setData</span>] = <span>useState</span>(() =&gt; <span>parse</span>(raw));</pre></div>\n</div>\n</div>\n<div class=\"hook-card\" id=\"useEffect\">\n<div class=\"hook-badge\">Effect</div>\n<div class=\"hook-name\">useEffect</div>\n<div class=\"hook-subtitle\">// side effects &amp; lifecycle</div>\n<p>Runs code AFTER render. Used for: fetching data, subscriptions, timers, DOM manipulation, third-party integrations.</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>useEffect</span>(() =&gt; {\n <span>const</span> <span>sub</span> = <span>subscribe</span>(userId);\n <span>return</span> () =&gt; sub.<span>unsubscribe</span>(); <span>// cleanup</span>\n}, [userId]); <span>// deps array controls when it runs</span></pre></div>\n</div>\n</div>\n<div class=\"hook-card\" id=\"useContext\">\n<div class=\"hook-badge\">Context</div>\n<div class=\"hook-name\">useContext</div>\n<div class=\"hook-subtitle\">// consume context values</div>\n<p>Reads a value from a React Context without prop-drilling. Like Django's template context \u2014 available to any descendant without explicitly passing it down.</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>const</span> <span>AuthCtx</span> = <span>createContext</span>(<span>null</span>);\n\n<span>// Provider wraps subtree</span>\n&lt;<span>AuthCtx.Provider</span> <span>value</span>=<span>{user}</span>&gt;\n &lt;<span>App</span> /&gt;\n&lt;/<span>AuthCtx.Provider</span>&gt;\n\n<span>// Any child consumes it</span>\n<span>const</span> <span>user</span> = <span>useContext</span>(AuthCtx);</pre></div>\n</div>\n</div>\n<div class=\"hook-card\" id=\"advanced-hooks\">\n<div class=\"hook-badge\">Ref</div>\n<div class=\"hook-name\">useRef</div>\n<div class=\"hook-subtitle\">// mutable reference, no re-render</div>\n<p>Like a box you can store anything in. Changing <code>.current</code> does NOT trigger re-render. Used for: DOM access, timers, storing previous values.</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>const</span> <span>inputRef</span> = <span>useRef</span>&lt;HTMLInputElement&gt;(<span>null</span>);\n<span>// Focus input on button click:</span>\n<span>inputRef</span>.current?.<span>focus</span>();\n<span>// Store a timer ID:</span>\n<span>const</span> <span>timerRef</span> = <span>useRef</span>&lt;NodeJS.Timeout&gt;();</pre></div>\n</div>\n</div>\n<div class=\"hook-card\">\n<div class=\"hook-badge\">Performance</div>\n<div class=\"hook-name\">useMemo</div>\n<div class=\"hook-subtitle\">// memoize expensive calculations</div>\n<p>Caches the result of a computation between renders. Only recomputes when dependencies change. Don't overuse \u2014 it has overhead. Use for truly expensive operations.</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>const</span> <span>sorted</span> = <span>useMemo</span>(() =&gt;\n [...items].<span>sort</span>((a, b) =&gt; a.price - b.price),\n [items] <span>// recompute only when items changes</span>\n);</pre></div>\n</div>\n</div>\n<div class=\"hook-card\">\n<div class=\"hook-badge\">Performance</div>\n<div class=\"hook-name\">useCallback</div>\n<div class=\"hook-subtitle\">// memoize function identity</div>\n<p>Returns the same function instance between renders unless deps change. Critical when passing callbacks to memoized child components to prevent unnecessary re-renders.</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>const</span> <span>handleClick</span> = <span>useCallback</span>(() =&gt; {\n <span>doSomething</span>(userId);\n}, [userId]); <span>// stable reference if userId same</span></pre></div>\n</div>\n</div>\n<div class=\"hook-card\">\n<div class=\"hook-badge\">State</div>\n<div class=\"hook-name\">useReducer</div>\n<div class=\"hook-subtitle\">// complex state logic</div>\n<p>Like Redux in miniature. Better than <code>useState</code> when state logic is complex or the next state depends on multiple conditions. Uses action-based updates.</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>function</span> <span>reducer</span>(state, action) {\n <span>switch</span>(action.type) {\n <span>case</span> <span>'increment'</span>: <span>return</span> { count: state.count + <span>1</span> };\n <span>default</span>: <span>return</span> state;\n }\n}\n<span>const</span> [<span>state</span>, <span>dispatch</span>] = <span>useReducer</span>(reducer, {count: <span>0</span>});</pre></div>\n</div>\n</div>\n<div class=\"hook-card\">\n<div class=\"hook-badge\">Custom</div>\n<div class=\"hook-name\">Custom Hooks</div>\n<div class=\"hook-subtitle\">// extract &amp; reuse logic</div>\n<p>Extract stateful logic into reusable functions. Must start with <code>use</code>. The best way to share logic between components \u2014 like Python utility functions, but for React state.</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>function</span> <span>useLocalStorage</span>&lt;T&gt;(key: <span>string</span>, init: T) {\n <span>const</span> [<span>value</span>, <span>setValue</span>] = <span>useState</span>&lt;T&gt;(\n () =&gt; <span>JSON</span>.<span>parse</span>(localStorage.<span>getItem</span>(key) ?? <span>'null'</span>) ?? init\n );\n <span>// syncs to localStorage on change</span>\n <span>useEffect</span>(() =&gt; { localStorage.<span>setItem</span>(key, <span>JSON</span>.<span>stringify</span>(value)); }, [key, value]);\n <span>return</span> [value, setValue] <span>as const</span>;\n}</pre></div>\n</div>\n</div>\n</div>\n</section>\n<section id=\"routing\">\n<div class=\"section-header\">\n<div class=\"section-num\">13</div>\n<div class=\"section-title-group\">\n<h2>React Router \u2014 <span class=\"tone-info\">Navigation</span></h2>\n<p>Client-side routing \u2014 no page reloads. Like Django URLs, but in the browser.</p>\n</div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Django URLs vs React Router</h4>\n<p>In Django, <code>urls.py</code> maps URL patterns to views on the SERVER. React Router maps URL patterns to components in the BROWSER. The browser intercepts navigation, renders the right component, and optionally fetches data \u2014 all without a server roundtrip.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">App.tsx \u2014 Router Setup (v7)</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { BrowserRouter, Routes, Route, Link, useParams, useNavigate, Outlet } <span>from</span> <span>'react-router-dom'</span>;\n\n<span>function</span> <span>App</span>() {\n <span>return</span> (\n &lt;<span>BrowserRouter</span>&gt;\n &lt;<span>nav</span>&gt;\n &lt;<span>Link</span> <span>to</span>=<span>\"/\"</span>&gt;Home&lt;/<span>Link</span>&gt; <span>// like {% url 'home' %}</span>\n &lt;<span>Link</span> <span>to</span>=<span>\"/users\"</span>&gt;Users&lt;/<span>Link</span>&gt;\n &lt;/<span>nav</span>&gt;\n &lt;<span>Routes</span>&gt;\n <span>// like urlpatterns = [path('', view)]</span>\n &lt;<span>Route</span> <span>path</span>=<span>\"/\"</span> <span>element</span>=<span>{&lt;HomePage /&gt;}</span> /&gt;\n &lt;<span>Route</span> <span>path</span>=<span>\"/users\"</span> <span>element</span>=<span>{&lt;UsersLayout /&gt;}</span>&gt;\n &lt;<span>Route</span> <span>index</span> <span>element</span>=<span>{&lt;UsersList /&gt;}</span> /&gt; <span>// /users</span>\n &lt;<span>Route</span> <span>path</span>=<span>\":id\"</span> <span>element</span>=<span>{&lt;UserDetail /&gt;}</span> /&gt; <span>// /users/42</span>\n &lt;/<span>Route</span>&gt;\n &lt;<span>Route</span> <span>path</span>=<span>\"*\"</span> <span>element</span>=<span>{&lt;NotFound /&gt;}</span> /&gt; <span>// 404</span>\n &lt;/<span>Routes</span>&gt;\n &lt;/<span>BrowserRouter</span>&gt;\n );\n}\n\n<span>// Nested layout with Outlet</span>\n<span>function</span> <span>UsersLayout</span>() {\n <span>return</span> (\n &lt;<span>div</span>&gt;\n &lt;<span>h1</span>&gt;Users Section&lt;/<span>h1</span>&gt;\n &lt;<span>Outlet</span> /&gt; <span>// child routes render here</span>\n &lt;/<span>div</span>&gt;\n );\n}\n\n<span>// Access URL params: /users/42</span>\n<span>function</span> <span>UserDetail</span>() {\n <span>const</span> { <span>id</span> } = <span>useParams</span>(); <span>// like request.resolver_match.kwargs</span>\n <span>const</span> <span>navigate</span> = <span>useNavigate</span>();\n\n <span>const</span> <span>goBack</span> = () =&gt; <span>navigate</span>(-<span>1</span>); <span>// browser back</span>\n <span>const</span> <span>goHome</span> = () =&gt; <span>navigate</span>(<span>'/'</span>); <span>// like redirect()</span>\n <span>const</span> <span>goWithState</span> = () =&gt; <span>navigate</span>(<span>'/users'</span>, { state: { from: <span>'detail'</span> } });\n\n <span>return</span> &lt;<span>div</span>&gt;User ID: {id}&lt;/<span>div</span>&gt;;\n}</pre></div>\n</div>\n<div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Protected Routes</div>\n<p>Wrap routes with an auth check: if not logged in, redirect to <code>/login</code>. Create a <code>&lt;ProtectedRoute&gt;</code> component that checks your auth context.</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Lazy Loading</div>\n<p>Use <code>React.lazy()</code> + <code>Suspense</code> to code-split by route. Large pages only load when navigated to, shrinking initial bundle size dramatically.</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Search Params</div>\n<p>Use <code>useSearchParams()</code> hook to read/write URL query params (<code>?filter=active&amp;page=2</code>) as the single source of truth for filter/pagination state.</p>\n</div>\n</div>\n</section>\n<section id=\"forms\">\n<div class=\"section-header\">\n<div class=\"section-num\">14</div>\n<div class=\"section-title-group\">\n<h2>Forms \u2014 <span class=\"tone-tip\">Controlled vs Uncontrolled</span></h2>\n<p>The two philosophies of form handling. Master both, know when to use which.</p>\n</div>\n</div>\n<div class=\"two-col\">\n<div>\n<h3> Controlled Components</h3>\n<p>React state is the single source of truth. Every keypress updates state, state drives the input value. Verbose but fully controlled.</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>const</span> [<span>email</span>, <span>setEmail</span>] = <span>useState</span>(<span>''</span>);\n\n&lt;<span>input</span>\n <span>value</span>=<span>{email}</span>\n <span>onChange</span>=<span>{e =&gt; setEmail(e.target.value)}</span>\n/&gt;\n<span>// React controls the value</span></pre></div>\n</div>\n</div>\n<div>\n<h3> Uncontrolled Components</h3>\n<p>DOM manages the value. React reads it via a ref only when needed (on submit). Simpler for basic forms with no real-time validation.</p>\n<div class=\"code-block\">\n<div class=\"code-body\"><pre><span>const</span> <span>emailRef</span> = <span>useRef</span>&lt;HTMLInputElement&gt;(<span>null</span>);\n\n&lt;<span>input</span> <span>ref</span>=<span>{emailRef}</span> /&gt;\n<span>// Read on submit:</span>\nconsole.<span>log</span>(emailRef.current?.value);</pre></div>\n</div>\n</div>\n</div>\n<div class=\"divider\"><div class=\"divider-line\"></div><div class=\"divider-text\">// React Hook Form \u2014 The Professional Solution</div><div class=\"divider-line\"></div></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">LoginForm with React Hook Form + Zod</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { useForm } <span>from</span> <span>'react-hook-form'</span>;\n<span>import</span> { zodResolver } <span>from</span> <span>'@hookform/resolvers/zod'</span>;\n<span>import</span> { z } <span>from</span> <span>'zod'</span>;\n\n<span>// Define schema (like Django Forms class)</span>\n<span>const</span> <span>schema</span> = z.object({\n email: z.<span>string</span>().<span>email</span>(<span>'Invalid email'</span>),\n password: z.<span>string</span>().<span>min</span>(<span>8</span>, <span>'Min 8 characters'</span>),\n});\n\n<span>type</span> <span>FormData</span> = z.infer&lt;<span>typeof</span> schema&gt;;\n\n<span>function</span> <span>LoginForm</span>() {\n <span>const</span> { register, handleSubmit, formState: { errors, isSubmitting } }\n = <span>useForm</span>&lt;FormData&gt;({ resolver: <span>zodResolver</span>(schema) });\n\n <span>const</span> <span>onSubmit</span> = <span>async</span> (data: FormData) =&gt; {\n <span>await</span> <span>loginUser</span>(data); <span>// RHF handles async + prevents double-submit</span>\n };\n\n <span>return</span> (\n &lt;<span>form</span> <span>onSubmit</span>=<span>{handleSubmit(onSubmit)}</span>&gt;\n &lt;<span>input</span> {...<span>register</span>(<span>'email'</span>)} <span>type</span>=<span>\"email\"</span> /&gt;\n {errors.email <span>&amp;&amp;</span> &lt;<span>span</span>&gt;{errors.email.message}&lt;/<span>span</span>&gt;}\n\n &lt;<span>input</span> {...<span>register</span>(<span>'password'</span>)} <span>type</span>=<span>\"password\"</span> /&gt;\n {errors.password <span>&amp;&amp;</span> &lt;<span>span</span>&gt;{errors.password.message}&lt;/<span>span</span>&gt;}\n\n &lt;<span>button</span> <span>disabled</span>=<span>{isSubmitting}</span>&gt;\n {isSubmitting ? <span>'Logging in...'</span> : <span>'Log In'</span>}\n &lt;/<span>button</span>&gt;\n &lt;/<span>form</span>&gt;\n );\n}</pre></div>\n</div>\n</section>\n<section id=\"state-mgmt\">\n<div class=\"section-header\">\n<div class=\"section-num\">15</div>\n<div class=\"section-title-group\">\n<h2>Global <span class=\"tone-info\">State Management</span></h2>\n<p>When lifting state up isn't enough \u2014 managing state that spans your entire application.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>Not all state is equal. <strong>Local state</strong> (a modal is open) lives in a component. <strong>Shared state</strong> (the logged-in user) needs to be accessible everywhere. <strong>Server state</strong> (data from an API) has its own lifecycle. Choosing the right tool for each type of state is a core React architecture skill.</p>\n</div>\n<table class=\"comparison-table\">\n<thead>\n<tr><th>State Type</th><th>Example</th><th>Best Tool</th></tr>\n</thead>\n<tbody>\n<tr><td>Local UI state</td><td>Modal open, form input value</td><td><code>useState</code></td></tr>\n<tr><td>Shared client state</td><td>Auth user, theme, cart</td><td>Context + <code>useReducer</code> / Zustand</td></tr>\n<tr><td>Server state</td><td>Users list, product data, API responses</td><td>TanStack Query / SWR</td></tr>\n<tr><td>Complex client state</td><td>Large app with many interactions</td><td>Redux Toolkit</td></tr>\n<tr><td>URL state</td><td>Filters, pagination, tabs</td><td><code>useSearchParams</code></td></tr>\n</tbody>\n</table>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Zustand \u2014 The Modern Choice</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { create } <span>from</span> <span>'zustand'</span>;\n\n<span>// Define your store (like a Redux store, but 10x simpler)</span>\n<span>interface</span> <span>AuthStore</span> {\n <span>user</span>: User | <span>null</span>;\n <span>token</span>: <span>string</span> | <span>null</span>;\n <span>login</span>: (user: User, token: <span>string</span>) =&gt; <span>void</span>;\n <span>logout</span>: () =&gt; <span>void</span>;\n}\n\n<span>const</span> <span>useAuthStore</span> = <span>create</span>&lt;AuthStore&gt;((set) =&gt; ({\n user: <span>null</span>,\n token: <span>null</span>,\n login: (user, token) =&gt; <span>set</span>({ user, token }),\n logout: () =&gt; <span>set</span>({ user: <span>null</span>, token: <span>null</span> }),\n}));\n\n<span>// Use in ANY component \u2014 no Provider needed!</span>\n<span>function</span> <span>Navbar</span>() {\n <span>const</span> { user, logout } = <span>useAuthStore</span>();\n <span>return</span> &lt;<span>div</span>&gt;{user?.name} &lt;<span>button</span> <span>onClick</span>=<span>{logout}</span>&gt;Logout&lt;/<span>button</span>&gt;&lt;/<span>div</span>&gt;;\n}</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">TanStack Query \u2014 Server State</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { useQuery, useMutation, useQueryClient } <span>from</span> <span>'@tanstack/react-query'</span>;\n\n<span>// Fetching: caching, loading, error states, background refresh \u2014 ALL built in</span>\n<span>function</span> <span>UserList</span>() {\n <span>const</span> { data, isLoading, error } = <span>useQuery</span>({\n queryKey: [<span>'users'</span>],\n queryFn: () =&gt; <span>fetch</span>(<span>'/api/users'</span>).<span>then</span>(r =&gt; r.<span>json</span>()),\n staleTime: <span>5</span> * <span>60</span> * <span>1000</span>, <span>// don't refetch for 5 minutes</span>\n });\n\n <span>if</span> (isLoading) <span>return</span> &lt;<span>Spinner</span> /&gt;;\n <span>if</span> (error) <span>return</span> &lt;<span>ErrorMessage</span> <span>error</span>=<span>{error}</span> /&gt;;\n <span>return</span> &lt;<span>ul</span>&gt;{data.<span>map</span>(u =&gt; &lt;<span>li</span> <span>key</span>=<span>{u.id}</span>&gt;{u.name}&lt;/<span>li</span>&gt;)}&lt;/<span>ul</span>&gt;;\n}\n\n<span>// Mutations: POST/PUT/DELETE with optimistic updates</span>\n<span>function</span> <span>DeleteUser</span>({ id }: { id: number }) {\n <span>const</span> <span>qc</span> = <span>useQueryClient</span>();\n <span>const</span> <span>mutation</span> = <span>useMutation</span>({\n mutationFn: (id: number) =&gt; <span>fetch</span>(<span>`/api/users/</span>${id}<span>`</span>, { method: <span>'DELETE'</span> }),\n onSuccess: () =&gt; qc.<span>invalidateQueries</span>({ queryKey: [<span>'users'</span>] }), <span>// refetch!</span>\n });\n\n <span>return</span> &lt;<span>button</span> <span>onClick</span>=<span>{() =&gt; mutation.mutate(id)}</span>&gt;Delete&lt;/<span>button</span>&gt;;\n}</pre></div>\n</div>\n</section>\n<section id=\"api\">\n<div class=\"section-header\">\n<div class=\"section-num\">16</div>\n<div class=\"section-title-group\">\n<h2>API &amp; <span>Data Fetching</span></h2>\n<p>How React apps communicate with your Django (or any) backend</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">services/api.ts \u2014 API Layer</span>\n<span class=\"code-lang\">TS</span>\n</div>\n<div class=\"code-body\"><pre><span>// Centralize all API calls \u2014 like Django's views, but client-side</span>\n<span>const</span> <span>BASE_URL</span> = <span>import.meta</span>.env.VITE_API_URL ?? <span>'http://localhost:8000'</span>;\n\n<span>async function</span> <span>apiFetch</span>&lt;T&gt;(path: <span>string</span>, options?: RequestInit): Promise&lt;T&gt; {\n <span>const</span> <span>token</span> = <span>localStorage</span>.<span>getItem</span>(<span>'token'</span>);\n <span>const</span> <span>res</span> = <span>await</span> <span>fetch</span>(<span>`</span>${BASE_URL}${path}<span>`</span>, {\n ...options,\n headers: {\n <span>'Content-Type'</span>: <span>'application/json'</span>,\n ...(token ? { Authorization: <span>`Bearer </span>${token}<span>`</span> } : {}),\n ...options?.headers,\n },\n });\n\n <span>if</span> (!res.ok) {\n <span>const</span> <span>error</span> = <span>await</span> res.<span>json</span>().<span>catch</span>(() =&gt; ({}));\n <span>throw</span> <span>new</span> <span>Error</span>(error.message ?? <span>`HTTP </span>${res.status}<span>`</span>);\n }\n <span>return</span> res.<span>json</span>();\n}\n\n<span>// Domain-specific API functions</span>\n<span>export const</span> <span>userApi</span> = {\n getAll: () =&gt; <span>apiFetch</span>&lt;User[]&gt;(<span>'/api/users/'</span>),\n getById: (id: <span>number</span>) =&gt; <span>apiFetch</span>&lt;User&gt;(<span>`/api/users/</span>${id}<span>/`</span>),\n create: (data: Partial&lt;User&gt;) =&gt; <span>apiFetch</span>&lt;User&gt;(<span>'/api/users/'</span>, {\n method: <span>'POST'</span>, body: <span>JSON</span>.<span>stringify</span>(data),\n }),\n update: (id: <span>number</span>, data: Partial&lt;User&gt;) =&gt; <span>apiFetch</span>&lt;User&gt;(<span>`/api/users/</span>${id}<span>/`</span>, {\n method: <span>'PATCH'</span>, body: <span>JSON</span>.<span>stringify</span>(data),\n }),\n delete: (id: <span>number</span>) =&gt; <span>apiFetch</span>&lt;<span>void</span>&gt;(<span>`/api/users/</span>${id}<span>/`</span>, { method: <span>'DELETE'</span> }),\n};</pre></div>\n</div>\n</section>\n<section id=\"testing\">\n<div class=\"section-header\">\n<div class=\"section-num\">17</div>\n<div class=\"section-title-group\">\n<h2>Testing \u2014 <span class=\"tone-info\">Confidence at Scale</span></h2>\n<p>The React testing philosophy: test behavior, not implementation.</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>\"The more your tests resemble the way your software is used, the more confidence they can give you.\" \u2014 Kent C. Dodds, author of Testing Library. Don't test <em>how</em> a component renders internally. Test <em>what the user sees and does</em>.</p>\n<div>// Test behavior, not implementation details</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Counter.test.tsx \u2014 Vitest + Testing Library</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { render, screen, fireEvent } <span>from</span> <span>'@testing-library/react'</span>;\n<span>import</span> { describe, it, expect } <span>from</span> <span>'vitest'</span>;\n<span>import</span> { Counter } <span>from</span> <span>'./Counter'</span>;\n\n<span>describe</span>(<span>'Counter'</span>, () =&gt; {\n <span>it</span>(<span>'renders with initial count of 0'</span>, () =&gt; {\n <span>render</span>(&lt;<span>Counter</span> /&gt;);\n <span>expect</span>(screen.<span>getByText</span>(<span>'Count: 0'</span>)).<span>toBeInTheDocument</span>();\n });\n\n <span>it</span>(<span>'increments when + button is clicked'</span>, () =&gt; {\n <span>render</span>(&lt;<span>Counter</span> /&gt;);\n fireEvent.<span>click</span>(screen.<span>getByRole</span>(<span>'button'</span>, { name: /\\+/ }));\n <span>expect</span>(screen.<span>getByText</span>(<span>'Count: 1'</span>)).<span>toBeInTheDocument</span>();\n });\n\n <span>it</span>(<span>'fetches and displays user data'</span>, <span>async</span> () =&gt; {\n <span>// Mock the API call</span>\n vi.<span>mock</span>(<span>'./api'</span>, () =&gt; ({\n fetchUser: vi.<span>fn</span>().<span>mockResolvedValue</span>({ name: <span>'Alice'</span> })\n }));\n\n <span>render</span>(&lt;<span>UserProfile</span> <span>id</span>=<span>{1}</span> /&gt;);\n <span>expect</span>(screen.<span>getByText</span>(<span>'Loading...'</span>)).<span>toBeInTheDocument</span>();\n\n <span>// Wait for async update</span>\n <span>expect</span>(<span>await</span> screen.<span>findByText</span>(<span>'Alice'</span>)).<span>toBeInTheDocument</span>();\n });\n});</pre></div>\n</div>\n<div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Test Pyramid</div>\n<p><strong>Many unit tests</strong> (hooks, utils), <strong>some integration tests</strong> (components with context), <strong>few E2E tests</strong> (Playwright/Cypress for critical user flows).</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Query Priority</div>\n<p>Prefer: <code>getByRole</code> \u2192 <code>getByLabelText</code> \u2192 <code>getByText</code> \u2192 <code>getByTestId</code>. Use accessible queries \u2014 they mirror how screen readers find elements.</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Setup</div>\n<p><code>npm install -D vitest @testing-library/react @testing-library/user-event jsdom @testing-library/jest-dom</code>. Vitest is Vite-native and blazing fast.</p>\n</div>\n</div>\n</section>\n<section id=\"performance\">\n<div class=\"section-header\">\n<div class=\"section-num\">18</div>\n<div class=\"section-title-group\">\n<h2>Performance <span class=\"tone-tip\">Optimization</span></h2>\n<p>Make React fast \u2014 but measure first. Don't optimize what doesn't need it.</p>\n</div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Premature Optimization is the Root of Evil</h4>\n<p>React is already fast. Add <code>memo</code>, <code>useMemo</code>, <code>useCallback</code> only when you've <strong>measured a real performance problem</strong> with React DevTools Profiler. These optimizations have a cost \u2014 don't add them everywhere.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Performance Patterns</span>\n<span class=\"code-lang\">TSX</span>\n</div>\n<div class=\"code-body\"><pre><span>import</span> { memo, useMemo, useCallback, lazy, Suspense } <span>from</span> <span>'react'</span>;\n\n<span>// 1. React.memo \u2014 skip re-render if props unchanged</span>\n<span>const</span> <span>ExpensiveList</span> = <span>memo</span>(({ items }: { items: Item[] }) =&gt; {\n <span>return</span> &lt;<span>ul</span>&gt;{items.<span>map</span>(i =&gt; &lt;<span>li</span> <span>key</span>=<span>{i.id}</span>&gt;{i.name}&lt;/<span>li</span>&gt;)}&lt;/<span>ul</span>&gt;;\n});\n\n<span>// 2. Code splitting \u2014 load page only when needed</span>\n<span>const</span> <span>Dashboard</span> = <span>lazy</span>(() =&gt; <span>import</span>(<span>'./pages/Dashboard'</span>));\n\n<span>function</span> <span>App</span>() {\n <span>return</span> (\n &lt;<span>Suspense</span> <span>fallback</span>=<span>{&lt;Spinner /&gt;}</span>&gt;\n &lt;<span>Dashboard</span> /&gt; <span>// loaded lazily</span>\n &lt;/<span>Suspense</span>&gt;\n );\n}\n\n<span>// 3. Virtualization \u2014 render only visible items</span>\n<span>// npm install @tanstack/react-virtual</span>\n<span>import</span> { useVirtualizer } <span>from</span> <span>'@tanstack/react-virtual'</span>;\n<span>// Renders 10,000 items without freezing the browser</span>\n\n<span>// 4. Image optimization</span>\n<span>// Use loading=\"lazy\" for below-fold images:</span>\n&lt;<span>img</span> <span>src</span>=<span>\"photo.jpg\"</span> <span>loading</span>=<span>\"lazy\"</span> <span>alt</span>=<span>\"...\"</span> /&gt;</pre></div>\n</div>\n<div class=\"concept-grid\">\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Profile First</h3>\n<p>Use React DevTools Profiler to record renders. Find which components render unnecessarily. Flame graphs show exact render times per component.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Code Splitting</h3>\n<p><code>React.lazy()</code> + <code>Suspense</code> splits your bundle by route. Users only download the JS for the pages they visit. Reduces initial load from 5MB to 200KB.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>List Virtualization</h3>\n<p>For lists with 100+ items, only render what's visible on screen. <code>@tanstack/react-virtual</code> handles this elegantly with near-zero overhead.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-tip\"></div>\n<h3>State Colocation</h3>\n<p>Keep state as close as possible to where it's used. Lifting state too high causes unnecessary re-renders of the whole tree. Colocate for performance.</p>\n</div>\n</div>\n</section>\n<section id=\"patterns\">\n<div class=\"section-header\">\n<div class=\"section-num\">19</div>\n<div class=\"section-title-group\">\n<h2>Advanced <span class=\"tone-info\">Patterns</span></h2>\n<p>The design patterns that separate junior from senior React developers</p>\n</div>\n</div>\n<div class=\"step-list\">\n<div class=\"step\">\n<div class=\"step-num\">1</div>\n<div class=\"step-content\">\n<h4>Error Boundaries</h4>\n<p>React's equivalent of Django's <code>500.html</code> error page \u2014 but per-component. Wrap sections of your UI to catch JS errors and show a fallback instead of crashing the whole app. Must be a class component (or use <code>react-error-boundary</code> library).</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">2</div>\n<div class=\"step-content\">\n<h4>Render Props / Children as Function</h4>\n<p>Pass a function as <code>children</code> to let parent components control rendering logic. Enables highly reusable components like <code>&lt;DataFetcher render={(data) =&gt; &lt;List data={data} /&gt;} /&gt;</code>.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">3</div>\n<div class=\"step-content\">\n<h4>Compound Components Pattern</h4>\n<p>Components that share state implicitly. <code>&lt;Select&gt;&lt;Option&gt;</code> pattern. The parent manages state, children are dumb. Uses Context internally to avoid prop-drilling between tightly coupled component families.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">4</div>\n<div class=\"step-content\">\n<h4>Portal Pattern</h4>\n<p><code>ReactDOM.createPortal()</code> renders a component outside its DOM parent \u2014 perfect for modals, tooltips, dropdowns that need to escape CSS overflow/z-index constraints. The component still belongs to the React tree.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">5</div>\n<div class=\"step-content\">\n<h4>Suspense + Concurrent Features</h4>\n<p>React 18's concurrent mode allows React to pause rendering, prioritize urgent updates, and progressively stream content. <code>&lt;Suspense&gt;</code> shows loading states declaratively while async data loads.</p>\n</div>\n</div>\n</div>\n</section>\n<section id=\"tooling\">\n<div class=\"section-header\">\n<div class=\"section-num\">20</div>\n<div class=\"section-title-group\">\n<h2>Tooling &amp; <span>Deployment</span></h2>\n<p>The professional React developer's toolkit \u2014 from dev to production</p>\n</div>\n</div>\n<div class=\"concept-grid\">\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Vite</h3>\n<p>Build tool. Replaces webpack for speed. Instant HMR, native ESM, ultra-fast production builds. The standard for new React projects.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>TypeScript</h3>\n<p>Type safety for React. Catches bugs before runtime. <code>interface Props</code> for component types. Essential for any serious project.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\"></div>\n<h3>Tailwind CSS</h3>\n<p>Utility-first CSS in JSX. <code>&lt;div className=\"flex items-center gap-4\"&gt;</code>. Co-located styles, no naming conflicts, no context switching.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-tip\"></div>\n<h3>ESLint + Prettier</h3>\n<p>ESLint with <code>eslint-plugin-react-hooks</code> enforces Rules of Hooks. Prettier formats code. Run in pre-commit hooks via <code>husky</code>.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Vitest</h3>\n<p>Vite-native test runner. Compatible with Jest's API. Extremely fast. Works with Testing Library out of the box.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\"></div>\n<h3>Vercel / Netlify</h3>\n<p>One-command deploy. Push to GitHub \u2192 auto-deploy. Free tier generous. Or deploy static build to any CDN: <code>npm run build</code> \u2192 upload <code>dist/</code>.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Essential Dependencies</span>\n<span class=\"code-lang\">BASH</span>\n</div>\n<div class=\"code-body\"><pre><span># Routing</span>\nnpm install react-router-dom\n\n<span># Forms + Validation</span>\nnpm install react-hook-form zod @hookform/resolvers\n\n<span># Server State Management</span>\nnpm install @tanstack/react-query\n\n<span># Client State</span>\nnpm install zustand\n\n<span># Styling</span>\nnpm install -D tailwindcss @tailwindcss/vite\n\n<span># Testing</span>\nnpm install -D vitest @testing-library/react @testing-library/user-event jsdom @testing-library/jest-dom\n\n<span># Component Docs</span>\nnpm install -D storybook\n\n<span># Linting</span>\nnpm install -D eslint eslint-plugin-react-hooks @typescript-eslint/parser prettier</pre></div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Full-Stack? Use Next.js</h4>\n<p>If you want SSR (server-side rendering like Django), API routes, file-based routing, and image optimization out of the box \u2014 <strong>Next.js</strong> is the production choice. It's React + a server framework, roughly analogous to Django in the React world. <code>npx create-next-app@latest</code></p>\n</div>\n</div>\n<!-- Final comparison table -->\n<div class=\"divider\"><div class=\"divider-line\"></div><div class=\"divider-text\">// Django vs React \u2014 The Complete Map</div><div class=\"divider-line\"></div></div>\n<table class=\"comparison-table\">\n<thead>\n<tr><th>Django Concept</th><th>React Equivalent</th><th>Notes</th></tr>\n</thead>\n<tbody>\n<tr><td><code>models.py</code></td><td>TypeScript interfaces</td><td>Type definitions, no ORM (backend handles DB)</td></tr>\n<tr><td><code>views.py</code></td><td>Components + hooks</td><td>Components render UI; hooks handle logic</td></tr>\n<tr><td><code>urls.py</code></td><td>React Router routes</td><td>Client-side, no server roundtrip</td></tr>\n<tr><td><code>forms.py</code></td><td>React Hook Form + Zod</td><td>Validation happens client-side</td></tr>\n<tr><td><code>templates/</code></td><td>JSX in components</td><td>Logic and template co-located</td></tr>\n<tr><td><code>static/</code></td><td><code>public/</code> + imports</td><td>Vite bundles and optimizes assets</td></tr>\n<tr><td><code>settings.py</code></td><td><code>vite.config.ts</code> + <code>.env</code></td><td>Environment-based config</td></tr>\n<tr><td><code>manage.py</code></td><td><code>package.json scripts</code></td><td><code>npm run dev/build/test</code></td></tr>\n<tr><td>Middleware</td><td>Higher-Order Components / Wrappers</td><td>Auth guards, logging, error boundaries</td></tr>\n<tr><td>Django Admin</td><td>Build your own admin UI</td><td>Or use Retool / AdminJS / Refine</td></tr>\n<tr><td>Signals</td><td>Custom events / Zustand subscriptions</td><td>React to state changes across the app</td></tr>\n<tr><td><code>wsgi.py</code></td><td><code>main.tsx</code></td><td>App entry point, mounts to DOM</td></tr>\n<tr><td><code>tests.py</code></td><td><code>*.test.tsx</code> with Vitest</td><td>Testing Library for behavior testing</td></tr>\n<tr><td>Celery tasks</td><td>Web Workers / async background</td><td>Heavy computation off main thread</td></tr>\n<tr><td>Session auth</td><td>JWT tokens + Zustand/Context</td><td>Token stored in memory or httpOnly cookie</td></tr>\n</tbody>\n</table>\n</section>";

